#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int ok = 1;
        for (int i = 1; i <= N; ++i) {
            int x; scanf("%d", &x);
            if (abs(x - i) > 1) ok = 0;
        }
        printf(ok ? "YES\n" : "NO\n");
    }
    return 0;
}

